body.script:
//
// White particle system
(function() {
  var canvas = document.getElementById('particles-canvas');
  var ctx = canvas.getContext('2d');
  var particles = [];
  var mouseX = -1000;
  var mouseY = -1000;

  function resize() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  }
  window.addEventListener('resize', resize);
  resize();

  canvas.addEventListener('mousemove', function(e) {
    mouseX = e.clientX;
    mouseY = e.clientY;
  });

  canvas.addEventListener('mouseleave', function() {
    mouseX = -1000;
    mouseY = -1000;
  });

  function Particle() {
    this.x = Math.random() * canvas.width;
    this.y = Math.random() * canvas.height;
    this.size = Math.random() * 2 + 0.5;
    this.speedX = (Math.random() - 0.5) * 0.3;
    this.speedY = (Math.random() - 0.5) * 0.3;
    this.opacity = Math.random() * 0.3 + 0.05;
  }

  Particle.prototype.update = function() {
    this.x += this.speedX;
    this.y += this.speedY;

    var dx = mouseX - this.x;
    var dy = mouseY - this.y;
    var dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < 120) {
      var force = (120 - dist) / 120 * 0.2;
      this.x -= dx / dist * force;
      this.y -= dy / dist * force;
    }

    if (this.x < 0) this.x = canvas.width;
    if (this.x > canvas.width) this.x = 0;
    if (this.y < 0) this.y = canvas.height;
    if (this.y > canvas.height) this.y = 0;
  };

  Particle.prototype.draw = function() {
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255, 255, 255, ' + this.opacity + ')';
    ctx.fill();
  };

  function initParticles(count) {
    particles = [];
    for (var i = 0; i < count; i++) {
      particles.push(new Particle());
    }
  }

  function drawLines() {
    for (var i = 0; i < particles.length; i++) {
      for (var j = i + 1; j < particles.length; j++) {
        var dx = particles[i].x - particles[j].x;
        var dy = particles[i].y - particles[j].y;
        var dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 100) {
          var opacity = (1 - dist / 100) * 0.04;
          ctx.beginPath();
          ctx.moveTo(particles[i].x, particles[i].y);
          ctx.lineTo(particles[j].x, particles[j].y);
          ctx.strokeStyle = 'rgba(255, 255, 255, ' + opacity + ')';
          ctx.lineWidth = 0.5;
          ctx.stroke();
        }
      }
    }
  }

  function animate() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (var i = 0; i < particles.length; i++) {
      particles[i].update();
      particles[i].draw();
    }
    drawLines();
    requestAnimationFrame(animate);
  }

  initParticles(100);
  animate();
})();

// Main scramjet logic
(function() {
  "use strict";

  var BASE_PATH = location.pathname.replace(/\/[^\/]*$/, "/");
  var swAllowedHostnames = ["localhost", "127.0.0.1"];

  var form = document.getElementById("sj-form");
  var address = document.getElementById("sj-address");
  var searchEngine = document.getElementById("sj-search-engine");
  var frameWrapper = document.getElementById("sj-frame-wrapper");
  var frameElement = document.getElementById("sj-frame");
  var frameUrl = document.getElementById("sj-frame-url");
  var error = document.getElementById("sj-error");
  var errorCode = document.getElementById("sj-error-code");
  var closeFrameLink = document.getElementById("close-frame-link");
  var wispInput = document.getElementById("wisp-server");
  var shortcutBtns = document.querySelectorAll('.shortcut-btn');

  function search(input, template) {
    try { return new URL(input).toString(); } catch (e) {}
    try {
      var url = new URL("http://" + input);
      if (url.hostname.includes(".")) return url.toString();
    } catch (e) {}
    if (
      input.includes("zaka") ||
      input.includes("zaka13") ||
      input.includes("zaka's games") ||
      input.includes("ign_zaka13")
    ) {
      alert("Why you searching my name up?");
      alert("lmfao");
    }
    return template.replace("%s", encodeURIComponent(input));
  }

  async function registerSW() {
    if (!navigator.serviceWorker) {
      if (location.protocol !== "https:" && !swAllowedHostnames.includes(location.hostname))
        throw new Error("Service workers cannot be registered without https.");
      throw new Error("Your browser doesn't support service workers.");
    }
    await navigator.serviceWorker.register(BASE_PATH + "sw.js", {
      scope: BASE_PATH,
      updateViaCache: "none",
    });
  }

  // ESC to close frame
  document.addEventListener("keydown", function(e) {
    if (e.key === "Escape") {
      if (frameWrapper) {
        frameWrapper.style.display = "none";
        if (closeFrameLink) closeFrameLink.style.display = "none";
        // Remove focus from address bar to prevent re-triggering
        address.blur();
      }
    }
    // Enter to submit form if in address bar
    if (e.key === "Enter" && document.activeElement === address) {
      e.preventDefault();
      form.dispatchEvent(new Event('submit'));
    }
  });

  // Also close via link
  if (closeFrameLink) {
    closeFrameLink.addEventListener("click", function(e) {
      e.preventDefault();
      frameWrapper.style.display = "none";
      closeFrameLink.style.display = "none";
    });
  }

  function showErrorScreen(msg, details) {
    frameWrapper.style.display = "none";
    if (closeFrameLink) closeFrameLink.style.display = "none";
    error.textContent = msg || "something went wrong";
    errorCode.textContent = details || "";
  }

  var controller = null;
  var frame = null;
  var currentWisp = wispInput.value.trim() || "wss://wisp.zaka.qzz.io/wisp/";

  wispInput.addEventListener("change", function() {
    var val = this.value.trim();
    if (val) {
      currentWisp = val;
      if (controller) {
        controller = null;
        frame = null;
      }
    }
  });

  async function initController() {
    controller = null;
    frame = null;

    var Controller = window.$scramjetController.Controller;
    var config = window.$scramjetController.config;

    config.scramjetPath = location.origin + BASE_PATH + "scj/scj.js";
    config.wasmPath = location.origin + BASE_PATH + "scj/scj.wasm";
    config.injectPath = location.origin + BASE_PATH + "controller/controller.inject.js";
    config.prefix = BASE_PATH + "~sj/";

    var transport = new window.LibcurlTransport.LibcurlClient({
      wisp: currentWisp,
    });

    controller = new Controller({
      serviceworker: navigator.serviceWorker.controller,
      transport: transport,
    });
    await controller.wait();

    frame = controller.createFrame(frameElement);
    if (!frame) throw new Error("createFrame returned null");
  }

  async function navigate(url) {
    if (!url.startsWith("http")) url = "https://" + url;
    if (!frame) await initController();
    await frame.go(url);
    frameWrapper.style.display = "flex";
    if (closeFrameLink) closeFrameLink.style.display = "inline";
    try {
      var displayUrl = new URL(url);
      frameUrl.textContent = displayUrl.hostname + displayUrl.pathname;
    } catch (e) {
      frameUrl.textContent = url;
    }
  }

  window.navigateTo = function(url) {
    address.value = url;
    form.dispatchEvent(new Event('submit'));
  };

  form.addEventListener("submit", async function(event) {
    event.preventDefault();

    if (address.value.trim() === "") {
      alert("Please type your search/URL");
      return;
    }

    var url = search(address.value, searchEngine.value);

    try {
      await registerSW();
    } catch (err) {
      error.textContent = "Failed to register service worker.";
      errorCode.textContent = err.toString();
      throw err;
    }

    if (!navigator.serviceWorker.controller) {
      await new Promise(function(resolve) {
        navigator.serviceWorker.addEventListener("controllerchange", resolve, { once: true });
      });
    }

    try {
      await navigate(url);
    } catch (err) {
      showErrorScreen(err.message, err.stack);
    }
  });

  // Shortcut click handlers - load in proxy
  shortcutBtns.forEach(function(btn) {
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      var url = this.dataset.url;
      if (url) {
        address.value = url;
        form.dispatchEvent(new Event('submit'));
      }
    });
  });

  var goto = new URL(location.href).searchParams.get("goto");
  if (goto) {
    history.replaceState(null, "", location.pathname);
    address.value = goto;
    registerSW()
      .then(function() {
        if (!navigator.serviceWorker.controller) {
          return new Promise(function(resolve) {
            navigator.serviceWorker.addEventListener("controllerchange", resolve, { once: true });
          });
        }
      })
      .then(function() { return navigate(goto); })
      .catch(function(err) { showErrorScreen(err.message, err.stack); });
  }
})();
